module gray_code_counter(CLK, RST, Q);
input CLK, RST;
output [2:0] Q;
reg [2:0] Q;
reg [2:0] obf_binary_counter;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        obf_binary_counter <= 0;
        Q <= 0;
    end else begin
        obf_binary_counter <= obf_binary_counter + 1;
        Q <= (obf_binary_counter >> 1) ^ obf_binary_counter; // Convert binary to gray code
    end
end

endmodule
